function moveActiveSlot(delta) {
  const i = state.activeSlot;
  const j = i + delta;
  if (i < 0 || j < 0 || j >= state.slots.length) return;
  const tmp = state.slots[i];
  state.slots[i] = state.slots[j];
  state.slots[j] = tmp;
  state.activeSlot = j;
  markDirtyDrawOrder();
  refreshSlotUI();
  renderBoneTree();
}

