        const setupMix = math.clamp(Number(ikSetup && ikSetup.mix) || 0, 0, 1);
        const setupSoftness = Math.max(0, Number(ikSetup && ikSetup.softness) || 0);
        const setupBend = ikSetup ? ikSetup.bendPositive !== false : true;
